import { c as createRouter } from 'hono';
import { z } from 'zod';

const router = createRouter();

const TaskSchema = z.object({
  title: z.string().min(1),
  description: z.string(),
  assigneeId: z.string()
});

router.post('/create-task', async (c) => {
  const body = await c.req.json();
  const result = TaskSchema.safeParse(body);

  if (!result.success) {
    return c.status(400).json({ error: 'Invalid request payload' });
  }

  const { title, description, assigneeId } = result.data;

  // Assuming you have a function to get the caller's team ID
  const callerTeamId = await getCallerTeamId(c);

  if (!callerTeamId) {
    return c.status(403).json({ error: 'Unauthorized' });
  }

  // Insert the new task into the database
  try {
    const taskId = await insertTask({
      title,
      description,
      assigneeId,
      teamId: callerTeamId
    });

    return c.json({ taskId, message: 'Task created successfully' });
  } catch (error) {
    console.error('Error creating task:', error);
    return c.status(500).json({ error: 'Internal server error' });
  }
});

export default router;

// Dummy functions for demonstration purposes
async function getCallerTeamId(c) {
  // Implement logic to retrieve the caller's team ID from the request context
  return 'team123';
}

async function insertTask(task) {
  // Implement logic to insert the task into the database and return the task ID
  return 'task456';
}

